import { HttpClient } from "@angular/common/http";
import { Component, OnInit } from "@angular/core";
import { EnvService } from "src/app/core/services/env.service";
import { pagingService } from "src/app/core/services/paging.service";
import { sortingService } from "src/app/core/services/sorting.service";
import { IBranch } from "../../Models/References/Branch";
import { FormBuilder, FormGroup } from "@angular/forms";
import { DatePipe } from "@angular/common";
import { User } from "../../Models/Users/User";
import { addDays, isBefore, isToday } from "date-fns";
import isAfter from "date-fns/isAfter";
import { AlertService } from "src/app/core/services/alert.service";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";

@Component({
  selector: "app-users-temporary-suspension",
  templateUrl: "./users-temporary-suspension.page.html",
  styleUrls: ["./users-temporary-suspension.page.scss"],
})
export class UsersTemporarySuspensionPage implements OnInit {
  showLoader: boolean = false;
  isSearching: boolean = true;
  canEnableUser: boolean = false;

  validationErrors: string = "";

  org_code: string;
  branch_code: string;

  page = 1; // the page we are viewing

  users;
  filteredUsers = [];

  sortingIconClass: string;
  sortingIconParam: string;

  branches: IBranch[] = [];

  SearchForm: FormGroup = this.formBuilder.group({
    search_input: [""],
    branch_code: [""],
  });

  UserForm: FormGroup = this.formBuilder.group({
    user_name: [""],
    user_branch_code: [""],
    disable_user_from: [this.datePipe.transform(Date.now(), "yyyy-MM-dd")],
    disable_user_to: [this.datePipe.transform(Date.now(), "yyyy-MM-dd")],
  });

  constructor(
    private env: EnvService,
    private http: HttpClient,
    private formBuilder: FormBuilder,
    private datePipe: DatePipe,
    private sortingService: sortingService,
    private authService: MohassilAuthService,
    private alertService: AlertService,
    public pagingService: pagingService
  ) {}

  async ngOnInit() {
    await this.authService.getUserInfo().then((userInfo) => {
      this.org_code = userInfo.org_code;
      this.branch_code = userInfo.branch_code;
    });

    this.getUsers();
  }

  changePage(newPage: number): void {
    this.page = newPage;
  }

  async submit(enable: boolean = false) {
    if (this.validateRevision()) {
      if (await this.alertService.SaveAlert()) {
        this.showLoader = true;
        if (enable) {
          this.UserForm.patchValue({
            disable_user_from: null,
            disable_user_to: null,
          });
        }
        this.http
          .post(this.env.API_URL + `api/User/DisableUser`, {
            org_code: this.org_code,
            branch_code: this.UserForm.value.user_branch_code.toString(),
            user_name: this.UserForm.value.user_name,
            disable_user_from: this.UserForm.value.disable_user_from,
            disable_user_to: this.UserForm.value.disable_user_to,
          })
          .subscribe({
            next: (data) => {
              this.alertService.showAlertConfirm("تم الحفظ بنجاح", true);
              this.showLoader = false;
            },
            error: (error) => {
              this.alertService.showAlertError(error.error, false);

              this.showLoader = false;
            },
          });
      }
    } else {
      this.alertService.showAlertError(this.validationErrors, false);
    }
  }

  async getUsers() {
    this.showLoader = true;
    return this.http
      .get(this.env.API_URL + "api/User/GetUsers")
      .subscribe((data) => {
        this.users = data["entities"];
        this.branches = data["branches"];
        this.filteredUsers = this.users;

        this.filteredUsers.forEach((x) => {
          x.disable_user_from =
            x.disable_user_from != null
              ? this.dateFormat(x.disable_user_from)
              : "لا يوجد";
          x.disable_user_to =
            x.disable_user_to != null
              ? this.dateFormat(x.disable_user_to)
              : "لا يوجد";
        });

        this.showLoader = false;
      });
  }

  review(user: User) {
    this.isSearching = false;
    this.UserForm.patchValue({
      user_name: user.user_name,
      user_branch_code: user.branch_code,
      disable_user_from: user.disable_user_from,
      disable_user_to: user.disable_user_to,
    });

    if (user.disable_user_from && user.disable_user_to != "لا يوجد") {
      this.canEnableUser = true;
    } else {
      this.UserForm.patchValue({
        disable_user_from: this.datePipe.transform(Date.now(), "yyyy-MM-dd"),
        disable_user_to: this.datePipe.transform(Date.now(), "yyyy-MM-dd"),
      });
    }
  }

  cancel() {
    this.isSearching = true;
    this.canEnableUser = false;
  }

  searchForUsers() {
    this.page = 1;
    let user_name = this.SearchForm.value.search_input;
    let branch_code = this.SearchForm.value.branch_code;

    this.filteredUsers = this.users.filter(
      (v) =>
        (user_name == "" ||
          v.user_name.toLowerCase().match(user_name.toLowerCase())) &&
        (branch_code == "" || v.branch_code == branch_code)
    );
  }

  validateRevision(): boolean {
    this.validationErrors = "";
    let state: boolean = true;

    let currentDate = new Date(
      this.datePipe.transform(Date.now(), "yyyy-MM-dd")
    );

    let disable_user_from = new Date(
      this.datePipe.transform(
        this.UserForm.value.disable_user_from,
        "yyyy-MM-dd"
      )
    );

    let disable_user_to = new Date(
      this.datePipe.transform(this.UserForm.value.disable_user_to, "yyyy-MM-dd")
    );

    if (isAfter(disable_user_from, disable_user_to)) {
      this.validationErrors += "تاريخ انتهاء الوقف قبل تاريخ البدء<br>";
      state = false;
    }

    if (
      isBefore(disable_user_from, currentDate) &&
      this.UserForm.value.disable_user_from != null &&
      this.UserForm.value.disable_user_to != null
    ) {
      this.validationErrors += "يجب اختيار التاريخ بدءاً من تاريخ اليوم<br>";
      state = false;
    }

    return state;
  }

  dateFormat(date) {
    return this.datePipe.transform(date, "yyyy-MM-dd");
  }

  sortingTable(data: any, param: string) {
    this.sortingService.sortByParameter(data, param);
    this.sortingIconClass =
      this.sortingService.sortOrder === "asc"
        ? "arrow-down-outline"
        : "arrow-up-outline";
    this.sortingIconParam = param;
  }
}
